const asaasPayments = $("Sync Pagamentos Asaas").item.json.payments ?? [];
const crmPayments   = $("Buscar Pendentes no CRM").all().map(i => i.json);

const asaasMap = {};
for (const p of asaasPayments) {
  asaasMap[p.id] = p.status;
}

const divergentes = [];
for (const crm of crmPayments) {
  const asaasStatus = asaasMap[crm.asaas_id];
  if (asaasStatus && asaasStatus !== crm.status) {
    divergentes.push({
      asaas_id:    crm.asaas_id,
      crm_status:  crm.status,
      asaas_status: asaasStatus,
      client_name:  crm.client_name,
      due_date:     crm.due_date,
    });
  }
}

return divergentes.map(d => ({ json: d }));
